  let r: any;
  r = (() => { try { return { ok: true, value: fn() }; } catch (e: any) { return { ok: false, message: e?.message }; } })();
  if (!r.ok) return { variant: '_thrown', message: r.message };
  if (r.value?.then) return r.value.catch((e: any) => ({ variant: '_thrown', message: e?.message }));
